mapper.select:
SELECT COALESCE(SUM(amount), 0)
FROM transactions
WHERE uuid_user = #{userId}
  AND DATE_FORMAT(transaction_date, '%Y-%m') = #{yearMonth}
  AND type = #{type}
  AND deleted_at IS NULL

SELECT c.code AS category_code, c.name AS category_name, SUM(t.amount) AS amount
FROM transactions t
JOIN categories c ON t.uuid_category = c.uuid
WHERE t.uuid_user = #{userId}
  AND DATE_FORMAT(t.transaction_date, '%Y-%m') = #{yearMonth}
  AND t.type = #{type}
  AND t.deleted_at IS NULL
GROUP BY c.uuid, c.code, c.name
ORDER BY amount DESC
